content_text:

1094近藤 誠2026年1月30日 21時29分
geminiにスクリプト作ってもらいました

heic画像をファイル名順に並べて一枚のPDFに出力という簡単なスクリプトです
Googleドライブの左上の+選択→その他→Google Apps Script

コードを入れて（IDは入れてくださいね）保存→実行でさくっとできます。

以下コードです。参考になれば嬉しいです。

function imagesToPdf_FitSize() {
// ▼ここにフォルダのURLの「末尾のID部分」を入れてください
const folderId = ‘末尾のID部分’;

// PDFのファイル名
const pdfName = ‘画像まとめ_サイズ調整版.pdf’;

try {
const folder = DriveApp.getFolderById(folderId);
const files = folder.getFiles();
const fileList = [];

// 1. ファイルをリストに格納
while (files.hasNext()) {
const file = files.next();
const mime = file.getMimeType().toLowerCase();
if (mime.includes(‘jpeg’) || mime.includes(‘png’) || mime.includes(‘heic’) || mime.includes(‘heif’)) {
fileList.push(file);
}
}

// 2. ソート
fileList.sort(function(a, b) {
return a.getName().localeCompare(b.getName());
});

if (fileList.length === 0) {
Logger.log(‘画像なし’);
return;
}

// 3. ドキュメント作成
const doc = DocumentApp.create(‘TempDoc_Fit’);
const body = doc.getBody();

// ページの有効幅を設定（A4サイズで余白を除いたおおよその幅ポイント）
// これを超えると縮小します
const MAX_PAGE_WIDTH = 500;

const token = ScriptApp.getOAuthToken();

// 4. 画像貼り付けとリサイズ
for (let i = 0; i MAX_PAGE_WIDTH) {
const ratio = MAX_PAGE_WIDTH / originalWidth;
const newWidth = MAX_PAGE_WIDTH;
const newHeight = originalHeight * ratio;

img.setWidth(newWidth);
img.setHeight(newHeight);
}

} catch (e) {
Logger.log(‘貼り付けエラー: ‘ + file.getName());
}
}

doc.saveAndClose();

// 5. PDF保存
const pdfBlob = doc.getAs(MimeType.PDF).setName(pdfName);
folder.createFile(pdfBlob);

// 6. 一時ファイル削除
DriveApp.getFileById(doc.getId()).setTrashed(true);

Logger.log(‘完了しました！’);

} catch (e) {
Logger.log(‘エラー: ‘ + e.toString());
}
}
